from pathlib import Path
import json, traceback
from playwright.sync_api import sync_playwright
ROOT=Path(__file__).resolve().parents[1]
OUT=ROOT/'evidence'; OUT.mkdir(exist_ok=True)
PHOTO=Path('/mnt/data/v92_test_property.jpg')
RESULT=OUT/'v922_browser_test_results.json'
html=(ROOT/'index.html').read_text(); css=(ROOT/'styles/main.v9.2.2.css').read_text(); config=(ROOT/'config.v9.2.2.js').read_text().replace('apiBaseUrl: ""','apiBaseUrl: "https://worker.test"'); app=(ROOT/'js/app.v9.2.2.js').read_text()
html=html.replace('<link rel="stylesheet" href="styles/main.v9.2.2.css" />',f'<style>{css}</style>').replace('<script src="config.v9.2.2.js"></script>',f'<script>{config}</script>').replace('<script type="module" src="js/app.v9.2.2.js"></script>',f'<script>{app}</script>')
STORE='''(() => { const data=new Map(); const storage={get length(){return data.size},key(i){return Array.from(data.keys())[i]??null},getItem(k){k=String(k);return data.has(k)?data.get(k):null},setItem(k,v){data.set(String(k),String(v))},removeItem(k){data.delete(String(k))},clear(){data.clear()}}; Object.defineProperty(window,'localStorage',{configurable:true,value:storage});})();'''
TINY='data:image/jpeg;base64,'
health={'ok':True,'version':'9.2.2','realRenderingEnabled':True,'killSwitchOn':False,'testModeOn':False,'providerKeyPresent':True,'inviteCodesConfigured':True,'retentionPolicy':'no-store','approvedProvider':'openai-gpt-image-2','approvedBackend':'cloudflare-worker','pilotSpendCapUsd':5,'invitedTesterLimit':10,'perSessionLimit':1,'perIpDailyLimit':2,'maxCostPerRenderUsd':0.15,'oneImageOnly':True,'serverImageStorage':False}
requests=[]
def route_handler(route):
 req=route.request
 if req.url.endswith('/api/health'):
  route.fulfill(status=200,content_type='application/json',body=json.dumps(health)); return
 if req.url.endswith('/api/render') and req.method=='POST':
  body=req.post_data_json; requests.append(body)
  route.fulfill(status=200,content_type='application/json',body=json.dumps({'ok':True,'version':'9.2.2','requestId':'test-request','estimatedCostUsd':0.08,'reservedCostUsd':0.15,'result':{'imageDataUrl':TINY,'providerRequestId':'provider-test'}})); return
 route.fulfill(status=404,content_type='application/json',body='{}')
def page_for(ctx,w=390,h=844,errors=None):
 p=ctx.new_page(); p.set_viewport_size({'width':w,'height':h}); p.set_default_timeout(12000); p.on('pageerror',lambda e: errors.append(str(e)) if errors is not None else None); p.set_content(html.replace('<body>','<body><script>'+STORE+'</script>',1),wait_until='load'); p.wait_for_timeout(500); return p
def tab(p,name): p.evaluate('name=>activateTab(name)',name); p.wait_for_timeout(120)
def overflow(p): return p.evaluate('document.documentElement.scrollWidth-document.documentElement.clientWidth')
results=[]; errors=[]
with sync_playwright() as pw:
 browser=pw.chromium.launch(headless=True, executable_path='/usr/bin/chromium', args=['--no-sandbox']); ctx=browser.new_context(); ctx.route('https://worker.test/**',route_handler)
 try:
  p=page_for(ctx,390,844,errors)
  assert 'BUILD V9.2.2' in p.locator('body').inner_text().upper()
  tab(p,'explore'); p.locator('#photoInput').set_input_files(str(PHOTO)); p.wait_for_timeout(500); p.locator('#propertyType').select_option('under-building'); p.locator('#constraintSelect').select_option('shade-dark'); p.locator('#analyseBtn').click(); p.wait_for_timeout(350)
  tab(p,'dashboard'); assert p.locator('#dashboardConceptStageHost').count()==1; assert overflow(p)<=2
  tab(p,'ai'); p.wait_for_timeout(400)
  owner=p.locator('#ownerActivationPanel').inner_text().upper(); assert '5 OF 5 APPROVALS RECORDED' in owner and owner.count('APPROVED')>=5
  assert 'PROVIDER PATH READY' in p.locator('#ownerLiveSafetyState').inner_text().upper()
  assert p.locator('#activateOwnerPilotBtn').is_disabled()
  p.evaluate("window.scrollTo(0, document.querySelector('#ownerActivationPanel').offsetTop - 8)"); p.wait_for_timeout(800); owner_shot=OUT/'v922_owner_approved_mobile.png'; p.screenshot(path=str(owner_shot))
  p.locator('#renderSelectedFutureBtn').click(); p.wait_for_timeout(100); p.locator('#pilotAccessCode').fill('VAI-01-test-valid-code')
  for ident in ['confirmRenderPrivacy','confirmRenderImageUse','confirmRenderCost','confirmRenderConcept']: p.locator('#'+ident).check()
  p.locator('#confirmOneRenderBtn').click(); p.wait_for_timeout(900)
  text=p.locator('#aiRenderFlowStatus').inner_text().upper(); assert 'AI CONCEPT RENDER · NOT FINAL DESIGN' in text and 'OWNER-APPROVED PILOT RESULT' in text
  assert p.locator('#liveRenderResults img').count()==1
  assert requests and requests[0]['count']==1 and requests[0]['buildVersion']=='9.2.2' and requests[0]['accessCode']=='VAI-01-test-valid-code'
  assert requests[0]['metadataStripped'] is True and requests[0]['confirmRender'] is True and isinstance(requests[0]['calibration']['keepClearAreas'], list)
  p.locator('#liveRenderResults').scroll_into_view_if_needed(); p.wait_for_timeout(100); result_shot=OUT/'v922_provider_result_mobile.png'; p.screenshot(path=str(result_shot))
  failure_checks=[]
  for button,needle in [('#testTimeoutStateBtn','RENDER STOPPED AFTER THE TIME LIMIT'),('#testProviderErrorStateBtn','PROVIDER COULD NOT RETURN A USABLE IMAGE'),('#testBudgetLockStateBtn','REQUEST DID NOT PASS THE ACCESS, LIMIT OR BUDGET GATE')]:
   p.locator(button).click(); p.wait_for_timeout(80); state_text=p.locator('#aiRenderFlowStatus').inner_text().upper(); assert needle in state_text and 'USE FREE CALIBRATED OVERLAY' in state_text and 'BACK TO PILOT' in state_text; failure_checks.append(needle)
  p.locator('#resetOwnerSafeStateBtn').click(); p.wait_for_timeout(120); assert 'STOPPED ON THIS BROWSER' in p.locator('#ownerLiveSafetyState').inner_text().upper()
  p.locator('#checkPilotConnectionBtn').click(); p.wait_for_timeout(250); assert 'PROVIDER PATH READY' in p.locator('#ownerLiveSafetyState').inner_text().upper()
  assert overflow(p)<=2; p.close()
  widths=[]
  for w in (360,390,412,430,1440):
   q=page_for(ctx,w,900 if w==1440 else 844,errors); tab(q,'ai'); q.wait_for_timeout(250); ov=overflow(q); assert ov<=2,(w,ov); assert q.locator('#activateOwnerPilotBtn').is_disabled(); widths.append({'width':w,'overflow':ov}); q.close()
  if errors: raise AssertionError(errors)
  results.append({'case':'v9.2.2-owner-approved-one-render','status':'passed','owner_approvals':'5/5','worker_health':'ready (intercepted contract)','one_provider_request':True,'failure_states':failure_checks,'safe_browser_lock':'passed','core_preservation':'passed','viewports':widths,'screenshots':[str(owner_shot),str(result_shot)],'browser':'Chromium inline harness with mocked Worker contract'})
 except Exception as e:
  results.append({'case':'v9.2.2-owner-approved-one-render','status':'failed','error':str(e),'trace':traceback.format_exc(),'browser_errors':errors})
 finally:
  ctx.close(); browser.close()
RESULT.write_text(json.dumps(results,indent=2)); print(json.dumps(results,indent=2));
if any(x.get('status')!='passed' for x in results): raise SystemExit(1)
